(1,1,'A WordPress Commenter','wapuu@wordpress.example','https://wordpress.org/','','2026-05-18 21:41:08','2026-05-18 21:41:08','Hi, this is a comment.\nTo get started with moderating, editing, and deleting comments, please visit the Comments screen in the dashboard.\nCommenter avatars come from <a href=\"https://gravatar.com/\">Gravatar</a>.',0,'1','','comment',0,0);
