(650,109,'_elementor_data','[{\"id\":\"4afa973\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\",\"content_width\":\"full\"},\"elements\":[{\"id\":\"38f148b\",\"elType\":\"widget\",\"settings\":{\"title\":{\"$$type\":\"html-v3\",\"value\":{\"content\":{\"$$type\":\"string\",\"value\":\"SATU  Member Application\"},\"children\":[]}},\"link\":{\"$$type\":\"link\",\"value\":[]}},\"elements\":[],\"widgetType\":\"e-heading\",\"styles\":[],\"interactions\":[],\"editor_settings\":[],\"version\":\"0.0\"}],\"isInner\":false},{\"id\":\"f31067f\",\"elType\":\"container\",\"settings\":{\"flex_direction\":\"column\",\"content_width\":\"full\",\"width\":{\"unit\":\"%\",\"size\":100,\"sizes\":[]}},\"elements\":[{\"id\":\"9e9719a\",\"elType\":\"widget\",\"settings\":{\"editor\":\"<p>If your university is interested in becoming a member in the SATU Presidents\\u2019 Forum, please fill out the below form and send it to the International Secretariat at <em>satu[at]iitb.ac.in<\\/em>. <br \\/><br \\/>The Steering Committee will review the application at the annual meeting. Admission is approved upon the consent of a majority of the members. When matters of necessity arise, the Steering Committee can make decisions by voting through the circulation of a formal document.<\\/p><p>(LINK TO THE APPLICATION)<\\/p><p>For more information regarding the membership, see the section on <a href=\\\"\\/about-satu\\/#membership-guidelines\\\">Membership Guidelines.<\\/a><\\/p>\"},\"elements\":[],\"widgetType\":\"text-editor\"}],\"isInner\":false}]'),
