(756,57,'_elementor_element_cache','{\"timeout\":1779767471,\"value\":{\"content\":\"<div class=\\\"elementor-element elementor-element-3799476 e-con-full e-flex e-con e-parent\\\" data-id=\\\"3799476\\\" data-element_type=\\\"container\\\" data-e-type=\\\"container\\\">\\n\\t\\t\\t\\t<div class=\\\"elementor-element elementor-element-d5ccfcb elementor-widget elementor-widget-html\\\" data-id=\\\"d5ccfcb\\\" data-element_type=\\\"widget\\\" data-e-type=\\\"widget\\\" data-widget_type=\\\"html.default\\\">\\n\\t\\t\\t\\t\\t<style>\\n\\/* \\u2500\\u2500\\u2500 About SATU Section Menu \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500 *\\/\\n.satu-page-menu {\\n    width: 100%;\\n    background-color: #f8f4f0;\\n    border-top: 3px solid #6B1E1E;\\n    border-bottom: 3px solid #6B1E1E;\\n    padding: 0;\\n    margin-bottom: 40px;\\n    box-sizing: border-box;\\n}\\n\\n.satu-page-menu ul {\\n    list-style: none !important;\\n    margin: 0 !important;\\n    padding: 0 !important;\\n    display: flex;\\n    flex-wrap: wrap;\\n    justify-content: center;\\n}\\n\\n.satu-page-menu ul li {\\n    list-style: none !important;\\n    margin: 0 !important;\\n    padding: 0 !important;\\n}\\n\\n.satu-page-menu ul li a {\\n    display: block;\\n    padding: 14px 28px;\\n    font-family: Arial, Helvetica, sans-serif;\\n    font-size: 0.85rem;\\n    font-weight: 600;\\n    letter-spacing: 1.2px;\\n    text-transform: uppercase;\\n    color: #6B1E1E !important;\\n    text-decoration: none !important;\\n    position: relative;\\n    transition: color 0.25s ease, background 0.25s ease;\\n}\\n\\n.satu-page-menu ul li a::after {\\n    content: \'\';\\n    position: absolute;\\n    bottom: 0;\\n    left: 28px;\\n    right: 28px;\\n    height: 3px;\\n    background: #6B1E1E;\\n    transform: scaleX(0);\\n    transform-origin: center