(791,126,'_elementor_css','a:6:{s:4:\"time\";i:1779336932;s:5:\"fonts\";a:0:{}s:5:\"icons\";a:0:{}s:20:\"dynamic_elements_ids\";a:0:{}s:6:\"status\";s:4:\"file\";i:0;s:0:\"\";}'),
(792,126,'_elementor_element_cache','{\"timeout\":1779512889,\"value\":{\"content\":\"<div class=\"elementor-element elementor-element-a0e5a50 e-con-full e-flex e-con e-parent\" data-id=\"a0e5a50\" data-element_type=\"container\" data-e-type=\"container\">ntttt<div class=\"elementor-element elementor-element-878dfc4 elementor-widget elementor-widget-html\" data-id=\"878dfc4\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"html.default\">nttttt<!--n=============================================================nSATU WEBSITE - HOMEPAGE SLIDERn=============================================================nMANAGED BY: Dean IR Office, IIT BombaynLAST UPDATED: May 2026nnHOW THIS SLIDER WORKS:n- Each slide is a <div class=\"satu-slide\"> blockn- Each slide contains one image (your Canva poster)n- Clicking the image takes the visitor to the related post/pagen- The slider auto-plays every 5 secondsn- There are previous/next arrows and dot indicatorsnnCANVA POSTER DIMENSIONS:n- Use 1400 x 500 pixels in Canva (Landscape format)n- Export as PNG or JPGn- Upload via WP Admin u2192 Media u2192 Add Newn- Copy the file URL from the media librarynn=============================================================nHOW TO ADD A NEW SLIDE (currently 2 slides, max 5):n=============================================================n1. Design your poster in Canva (1400 x 500 px)n2. Upload it via WP Admin u2192 Media u2192 Add Newn3. Copy the image URL from the media libraryn4. Copy the block below and paste it before the closingn   </div> of id=\"satuSliderTrack\":nn   <div class=\"satu-slide\">n       <a href=\"PASTE-YOUR-POST-LINK-HERE\" target=\"_blank\">n           <img src=\"PASTE-YOUR-IMAGE-URL-HERE\" alt=\"Brief description\">n       </a>n   </div>nn5. Also add a new dot indicator inside id=\"satuDots\":n   <span class=\"satu-dot\" onclick=\"satuGoTo(N)\"></span>n   Replace N with the slide number starting from 0n   (slide 1 = 0, slide 2 = 1, slide 3 = 2, and so on)nn=============================================================nHOW TO REMOVE A SLIDE:n=============================================================nDelete the entire <div class=\"satu-slide\">...</div> blocknand remove the last <span> from id=\"satuDots\"nn=============================================================nHOW TO CHANGE THE AUTO-PLAY SPEED:n=============================================================nAt the bottom of this file, find:n   satuInterval = setInterval(satuNext, 5000);nChange 5000 to any number (in milliseconds)nExample: 3000 = 3 seconds, 7000 = 7 secondsnn=============================================================n-->nn<style>n.satu-slider-wrapper {n    width: 100%;n    overflow: hidden;n    position: relative;n    background: #111;n    user-select: none;n}nn.satu-slider-track {n    display: flex;n    transition: transform 0.5s ease-in-out;n    will-change: transform;n}nn.satu-slide {n    min-width: 100%;n    position: relative;n}nn.satu-slide a {n    display: block;n    width: 100%;n}nn.satu-slide img {n    width: 100%;n    height: auto;n    display: block;n    object-fit: cover;n}nn/* u2500u2500u2500 Arrows u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-arrow {n    position: absolute;n    top: 50%;n    transform: translateY(-50%);n    background: rgba(0, 0, 0, 0.35);n    color: #fff;n    border: none;n    font-size: 1.6rem;n    padding: 10px 16px;n    cursor: pointer;n    z-index: 10;n    border-radius: 3px;n    transition: background 0.2s ease;n    line-height: 1;n}n.satu-arrow:hover { background: rgba(0, 0, 0, 0.65); }n.satu-arrow.prev { left: 12px; }n.satu-arrow.next { right: 12px; }nn/* u2500u2500u2500 Dots u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-dots {n    position: absolute;n    bottom: 10px;n    width: 100%;n    display: flex;n    justify-content: center;n    gap: 8px;n}nn.satu-dot {n    width: 10px;n    height: 10px;n    border-radius: 50%;n    background: rgba(255, 255, 255, 0.45);n    cursor: pointer;n    transition: background 0.25s ease, transform 0.25s ease;n    display: inline-block;n}nn.satu-dot.active {n    background: #ffffff;n    transform: scale(1.25);n}nn/* u2500u2500u2500 Mobile u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n@media (max-width: 600px) {n    .satu-arrow { font-size: 1.1rem; padding: 7px 11px; }n}n</style>nn<!-- SLIDER HTML u2014 Edit image URLs and links below -->n<div class=\"satu-slider-wrapper\">nn    <div class=\"satu-slider-track\" id=\"satuSliderTrack\">nn        <!-- ==========================================n             SLIDE 1n             - Replace IMAGE-URL-1 with your Canva poster URLn             - Replace POST-LINK-1 with the page/post URLn             - Replace \"Description 1\" with a short descriptionn             ========================================== -->n        <div class=\"satu-slide\">n            <a href=\"POST-LINK-1\" target=\"_blank\">n                <img src=\"/wp-content/uploads/2026/05/hero_satu_second-scaled.jpg\" alt=\"Description 1\">n            </a>n        </div>nn        <!-- ==========================================n             SLIDE 2n             - Replace IMAGE-URL-2 with your Canva poster URLn             - Replace POST-LINK-2 with the page/post URLn             - Replace \"Description 2\" with a short descriptionn             ========================================== -->n        <div class=\"satu-slide\">n            <a href=\"POST-LINK-2\" target=\"_blank\">n                <img src=\"/wp-content/uploads/2026/05/hero_satu_first-scaled.jpg\" alt=\"Description 2\">n            </a>n        </div>nn        <!-- PASTE ADDITIONAL SLIDES HERE (max 3 more) -->nn    </div>nn    <button class=\"satu-arrow prev\" onclick=\"satuPrev()\">&#8249;</button>n    <button class=\"satu-arrow next\" onclick=\"satuNext()\">&#8250;</button>nn    <div class=\"satu-dots\" id=\"satuDots\">n        <span class=\"satu-dot active\" onclick=\"satuGoTo(0)\"></span>n        <span class=\"satu-dot\" onclick=\"satuGoTo(1)\"></span>n        <!-- ADD ONE MORE DOT HERE FOR EACH NEW SLIDE YOU ADD -->n        <!-- Example for slide 3: <span class=\"satu-dot\" onclick=\"satuGoTo(2)\"></span> -->n        <!-- Example for slide 4: <span class=\"satu-dot\" onclick=\"satuGoTo(3)\"></span> -->n        <!-- Example for slide 5: <span class=\"satu-dot\" onclick=\"satuGoTo(4)\"></span> -->n    </div>nn</div>nn<script>n(function () {n    var track   = document.getElementById(\'satuSliderTrack\');n    var dots    = document.querySelectorAll(\'#satuDots .satu-dot\');n    var current = 0;n    var total   = track.children.length;n    var satuInterval;nn    function satuGoTo(n) {n        current = (n + total) % total;n        track.style.transform = \'translateX(-\' + (current * 100) + \'%)\';n        dots.forEach(function (d) { d.classList.remove(\'active\'); });n        if (dots[current]) dots[current].classList.add(\'active\');n    }nn    function satuNext() { satuGoTo(current + 1); }n    function satuPrev() { satuGoTo(current - 1); }nn    // Auto-play u2014 change 5000 to adjust speed (milliseconds)n    satuInterval = setInterval(satuNext, 5000);nn    // Pause on hovern    track.parentElement.addEventListener(\'mouseenter\', function () {n        clearInterval(satuInterval);n    });n    track.parentElement.addEventListener(\'mouseleave\', function () {n        satuInterval = setInterval(satuNext, 5000);n    });nn    // Expose functions globally for onclick handlersn    window.satuGoTo = satuGoTo;n    window.satuNext = satuNext;n    window.satuPrev = satuPrev;n})();n</script>tttt</div>ntttt</div>ntt<div class=\"elementor-element elementor-element-90eb1bc e-con-full e-flex e-con e-parent\" data-id=\"90eb1bc\" data-element_type=\"container\" data-e-type=\"container\">ntttt<div class=\"elementor-element elementor-element-b162846 elementor-widget elementor-widget-html\" data-id=\"b162846\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"html.default\">nttttt<style>n/* u2500u2500u2500 Section Wrapper u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-cards-section {n    width: 100%;n    padding: 60px 48px;n    background-color: #ffffff;n    display: flex;n    justify-content: center;n    align-items: stretch;n    gap: 32px;n    box-sizing: border-box;n}nn/* u2500u2500u2500 Individual Card u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-card {n    flex: 1;n    max-width: 360px;n    background-color: #ffffff;n    border-radius: 8px;n    border: 1px solid #e0e0e0;n    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.08);n    padding: 40px 32px;n    display: flex;n    flex-direction: column;n    align-items: center;n    text-align: center;n    cursor: pointer;n    text-decoration: none;n    color: inherit;nn    /* Float animation setup */n    transition: transform 0.35s ease, box-shadow 0.35s ease, border-color 0.35s ease;n    transform: translateY(0);n}nn.satu-card:hover {n    transform: translateY(-10px);n    box-shadow: 0 16px 40px rgba(107, 30, 30, 0.18);n    border-color: #6B1E1E;n    text-decoration: none;n    color: inherit;n}nn/* u2500u2500u2500 Card Icon u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-card-icon {n    width: 64px;n    height: 64px;n    background-color: #6B1E1E;n    border-radius: 50%;n    display: flex;n    align-items: center;n    justify-content: center;n    margin-bottom: 24px;n    flex-shrink: 0;n    transition: background-color 0.35s ease;n}nn.satu-card:hover .satu-card-icon {n    background-color: #8B2525;n}nn.satu-card-icon svg {n    width: 30px;n    height: 30px;n    fill: #ffffff;n}nn/* u2500u2500u2500 Card Title u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-card-title {n    font-family: \"Palatino Linotype\", Palatino, Georgia, serif;n    font-size: 1.3rem;n    font-weight: 700;n    color: #6B1E1E;n    margin-bottom: 14px;n    line-height: 1.3;n}nn/* u2500u2500u2500 Card Description u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-card-desc {n    font-family: Arial, Helvetica, sans-serif;n    font-size: 0.88rem;n    color: #555555;n    line-height: 1.7;n    flex: 1;n    margin-bottom: 24px;n}nn/* u2500u2500u2500 Card Button u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-card-btn {n    display: inline-block;n    padding: 9px 24px;n    background-color: #6B1E1E;n    color: #ffffff !important;n    font-family: Arial, Helvetica, sans-serif;n    font-size: 0.82rem;n    font-weight: 600;n    letter-spacing: 1px;n    text-transform: uppercase;n    text-decoration: none !important;n    border-radius: 4px;n    transition: background-color 0.25s ease;n    margin-top: auto;n}nn.satu-card:hover .satu-card-btn {n    background-color: #8B2525;n}nn.satu-card,n.satu-card *,n.satu-card:hover,n.satu-card:hover * {n    text-decoration: none !important;n}nnn/* u2500u2500u2500 Tablet u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n@media (max-width: 900px) {n    .satu-cards-section {n        padding: 48px 28px;n        gap: 24px;n    }n}nn/* u2500u2500u2500 Mobile u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n@media (max-width: 650px) {n    .satu-cards-section {n        flex-direction: column;n        align-items: center;n        padding: 36px 20px;n        gap: 20px;n    }n    .satu-card {n        max-width: 100%;n        width: 100%;n        padding: 32px 24px;n    }n}n</style>nn<section class=\"satu-cards-section\">nn    <!-- u2500u2500 Card 1: About SATU u2500u2500 -->n    <a class=\"satu-card\" href=\"/about-satu/\">n        <div class=\"satu-card-icon\">n            <!-- Info / About icon -->n            <svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\">n                <path d=\"M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10n                         10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z\"/>n            </svg>n        </div>n        <div class=\"satu-card-title\">About SATU</div>n        <div class=\"satu-card-desc\">n            Learn about the SATU Presidents\' Forum u2014 its vision, mission,n            member universities across Southeast and South Asia and Taiwan,n            and IIT Bombay\'s role in this academic alliance.n        </div>n        <span class=\"satu-card-btn\">Learn More</span>n    </a>nn    <!-- u2500u2500 Card 2: Activities u2500u2500 -->n    <a class=\"satu-card\" href=\"/activities/\">n        <div class=\"satu-card-icon\">n            <!-- Calendar / Activities icon -->n            <svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\">n                <path d=\"M19 3h-1V1h-2v2H8V1H6v2H5C3.89 3 3 3.9 3 5v14n                         c0 1.1.89 2 2 2h14c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0n                         16H5V8h14v11zM7 10h5v5H7z\"/>n            </svg>n        </div>n        <div class=\"satu-card-title\">Activities</div>n        <div class=\"satu-card-desc\">n            Explore SATU\'s academic exchanges, joint research initiatives,n            webinar series, innovation competitions, and upcoming eventsn            hosted by member universities.n        </div>n        <span class=\"satu-card-btn\">Explore</span>n    </a>nn    <!-- u2500u2500 Card 3: Previous Website u2500u2500 -->n    <a class=\"satu-card\" href=\"https://satu.ncku.edu.tw/\" target=\"_blank\" rel=\"noopener noreferrer\">n        <div class=\"satu-card-icon\">n            <!-- External link icon -->n            <svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\">n                <path d=\"M19 19H5V5h7V3H5a2 2 0 00-2 2v14a2 2 0n                         002 2h14a2 2 0 002-2v-7h-2v7zM14 3v2h3.59n                         l-9.83 9.83 1.41 1.41L19 6.41V10h2V3h-7z\"/>n            </svg>n        </div>n        <div class=\"satu-card-title\">Previous Website</div>n        <div class=\"satu-card-desc\">n            Visit the original SATU Presidents\' Forum website hosted byn            National Cheng Kung University (NCKU), Taiwan for archives,n            past events, and historical records.n        </div>n        <span class=\"satu-card-btn\">Visit</span>n    </a>nn</section>tttt</div>ntttt</div>ntt<div class=\"elementor-element elementor-element-e19b0c2 e-con-full e-flex e-con e-parent\" data-id=\"e19b0c2\" data-element_type=\"container\" data-e-type=\"container\">ntt[elementor-element k=\"b06e607552cb2a428150a91ead3cad28\" data=\"\"]tt</div>ntt<div class=\"elementor-element elementor-element-2e1f275 e-con-full e-flex e-con e-parent\" data-id=\"2e1f275\" data-element_type=\"container\" data-e-type=\"container\">ntttt<div class=\"elementor-element elementor-element-663ab16 elementor-widget elementor-widget-html\" data-id=\"663ab16\" data-element_type=\"widget\" data-e-type=\"widget\" data-widget_type=\"html.default\">nttttt<style>n/* u2500u2500u2500 Contact Section u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-contact-section {n    width: 100%;n    padding: 60px 48px;n    display: flex;n    align-items: center;n    gap: 60px;n    box-sizing: border-box;n    background-color: #ffffff;n}nn/* u2500u2500u2500 Left: Text u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-contact-text {n    flex: 1;n    min-width: 260px;n}nn.satu-contact-text h2 {n    font-family: \"Palatino Linotype\", Palatino, Georgia, serif;n    font-size: 2rem;n    font-weight: 700;n    color: #6B1E1E;n    margin-bottom: 24px;n    line-height: 1.2;n}nn.satu-contact-text address {n    font-style: normal;n    font-family: Arial, Helvetica, sans-serif;n    font-size: 0.95rem;n    color: #444444;n    line-height: 2;n}nn.satu-contact-text address a {n    color: #6B1E1E;n    text-decoration: none;n}nn.satu-contact-text address a:hover {n    text-decoration: underline;n}nn/* u2500u2500u2500 Right: Map u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n.satu-contact-map {n    flex: 1.2;n    min-width: 300px;n    height: 320px;n    border-radius: 8px;n    overflow: hidden;n    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.12);n    border: 1px solid #e0e0e0;n}nn.satu-contact-map iframe {n    width: 100%;n    height: 100%;n    border: none;n    display: block;n}nn/* u2500u2500u2500 Tablet u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n@media (max-width: 900px) {n    .satu-contact-section {n        padding: 48px 28px;n        gap: 40px;n    }n}nn/* u2500u2500u2500 Mobile u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500u2500 */n@media (max-width: 650px) {n    .satu-contact-section {n        flex-direction: column;n        padding: 36px 20px;n        gap: 28px;n    }n    .satu-contact-map {n        width: 100%;n        height: 260px;n    }n    .satu-contact-text h2 {n        font-size: 1.6rem;n    }n}n</style>nn<section class=\"satu-contact-section\">nn    <!-- u2500u2500 Left: Address u2500u2500 -->n    <div class=\"satu-contact-text\">n        <h2>Contact Us</h2>n        <address>n            Office of the Dean (International Relations)<br>n            Indian Institute of Technology Bombay<br>n            Room 416, 4th Floor,<br>n            Rahul Bajaj Technology Innovation Centre (RBTIC) Building,<br>n            Powai, Mumbai u2013 400076<br>n            Indian        </address>n    </div>nn    <!-- u2500u2500 Right: Google Map (IIT Bombay Main Gate) u2500u2500 -->n    <div class=\"satu-contact-map\">n        <iframen            src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3769.9745765143!2d72.91355!3d19.13326!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3be7b6f5c2b0e6a7%3A0x6e9f8f9b6f9b6f9b!2sIIT%20Bombay%20Main%20Gate!5e0!3m2!1sen!2sin!4v1620000000000!5m2!1sen!2sin\"n            allowfullscreen=\"\"n            loading=\"lazy\"n            referrerpolicy=\"no-referrer-when-downgrade\"n            title=\"IIT Bombay Main Gate\">n        </iframe>n    </div>nn</section>tttt</div>ntttt</div>ntt\",\"scripts\":[],\"styles\":[]}}'),
