*/\\n.satu-mem-table {\\n    width: 100%;\\n    border-collapse: collapse;\\n    margin-top: 16px;\\n    margin-bottom: 24px;\\n    font-size: 0.90rem;\\n}\\n\\n.satu-mem-table th,\\n.satu-mem-table td {\\n    border: 1px solid #d0c0b0;\\n    padding: 12px 16px;\\n    text-align: left;\\n    vertical-align: top;\\n    color: #444444;\\n}\\n\\n.satu-mem-table th {\\n    background-color: #6B1E1E;\\n    color: #ffffff;\\n    font-weight: 600;\\n    letter-spacing: 0.5px;\\n}\\n\\n.satu-mem-table tr:nth-child(even) td {\\n    background-color: #f9f4f0;\\n}\\n\\n/* \\u2500\\u2500\\u2500 Mobile \\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500\\u2500 */\\n@media (max-width: 600px) {\\n    .satu-page-menu ul { flex-direction: column; }\\n    .satu-page-menu ul li a {\\n        padding: 12px 24px;\\n        border-bottom: 1px solid rgba(107, 30, 30, 0.12);\\n        font-size: 0.82rem;\\n    }\\n    .satu-page-menu ul li a::after { display: none; }\\n}\",\n        \"type\": \"custom_css\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-05-20 20:01:12\"\n    }\n}','','','trash','closed','closed','','8808acc2-8dd1-44bd-9d81-2c77122d07bc','','','2026-05-20 20:01:12','2026-05-20 20:01:12','',0,'http://10.18.33.196/index.php/2026/05/20/8808acc2-8dd1-44bd-9d81-2c77122d07bc/',0,'customize_changeset','',0),
(63,1,'2026-05-20 20:01:12','2026-05-20 20:01:12','/* ─── About SATU Page Content ────────────────────────────── */\n.satu-page-content {\n    max-width: 900px;\n    margin: 0 auto;\n    padding: 0 24px 60px;\n    font-family: Arial, Helvetica, sans-serif;\n    color: #333333;\n    line-height: 1.8;\n}\n\n.satu-section {\n    margin-bottom: 56px;\n    scroll-margin-top: 80px;\n}\n\n.satu-section h2 {\n    font-family: \"Palatino Linotype\", Palatino, Georgia, serif;\n    font-size: 1.7rem;\n    font-weight: 700;\n    color: #6B1E1E;\n    margin-bottom: 20px;\n    padding-bottom: 10px;\n    border-bottom: 2px solid #c8a96e;\n}\n\n.satu-section p {\n    font-size: 0.95rem;\n    margin-bottom: 14px;\n    color: #444444;\n}\n\n.satu-section ul {\n    padding-left: 24px;\n    margin-bottom: 14px;\n}\n\n.satu-section ul li {\n    font-size: 0.95rem;\n    color: #444444;\n    margin-bottom: 8px;\n    line-height: 1.7;\n}\n\n.satu-section .satu-subsection {\n    margin-top: 28px;\n    margin-bottom: 20px;\n}\n\n.satu-section .satu-subsection h3 {\n    font-family: \"Palatino Linotype\", Palatino, Georgia, serif;\n    font-size: 1.15rem;\n    font-weight: 700;\n    color: #4a1414;\n    margin-bottom: 10px;\n}\n\n.satu-section a {\n    color: #6B1E1E;\n    text-decoration: underline;\n}\n\n.satu-section a:hover {\n    color: #4a1414;\n}\n\n/* ─── Membership Table ───────────────────────────────────── */\n.satu-mem-table {\n    width: 100%;\n    border-collapse: collapse;\n    margin-top: 16px;\n    margin-bottom: 24px;\n    font-size: 0.90rem;\n}\n\n.satu-mem-table th,\n.satu-mem-table td {\n    border: 1px solid #d0c0b0;\n    padding: 12px 16px;\n    text-align: left;\n    vertical-align: top;\n    color: #444444;\n}\n\n.satu-mem-table th {\n    background-color: #6B1E1E;\n    color: #ffffff;\n    font-weight: 600;\n    letter-spacing: 0.5px;\n}\n\n.satu-mem-table tr:nth-child(even) td {\n    background-color: #f9f4f0;\n}\n\n/* ─── Mobile ─────────────────────────────────────────────── */\n@media (max-width: 600px) {\n    .satu-page-menu ul { flex-direction: column; }\n    .satu-page-menu ul li a {\n        padding: 12px 24px;\n        border-bottom: 1px solid rgba(107, 30, 30, 0.12);\n        font-size: 0.82rem;\n    }\n    .satu-page-menu ul li a::after { display: none; }\n}\n\n\n/* ─── Constitution Page ──────────────────────────────────── */\n.satu-constitution {\n    max-width: 860px;\n    margin: 0 auto;\n    padding: 40px 24px 60px;\n    font-family: Arial, Helvetica, sans-serif;\n    color: #333333;\n    line-height: 1.8;\n}\n\n.satu-constitution .satu-const-header {\n    text-align: center;\n    margin-bottom: 32px;\n    padding-bottom: 24px;\n    border-bottom: 2px solid #c8a96e;\n}\n\n.satu-constitution .satu-const-header h1 {\n    font-family: \"Palatino Linotype\", Palatino, Georgia, serif;\n    font-size: 1.15rem;\n    font-weight: 700;\n    color: #6B1E1E;\n    line-height: 1.6;\n    margin-bottom: 16px;\n    text-transform: uppercase;\n    letter-spacing: 1px;\n}\n\n.satu-constitution .satu-const-amendments {\n    text-align: right;\n    font-size: 0.85rem;\n    color: #666666;\n    line-height: 2;\n    font-style: italic;\n}\n\n.satu-constitution .satu-const-article {\n    margin-bottom: 40px;\n}\n\n.satu-constitution .satu-const-article h2 {\n    font-family: Arial, Helvetica, sans-serif;\n    font-size: 0.95rem;\n    font-weight: 700;\n    color: #6B1E1E;\n    text-transform: uppercase;\n    letter-spacing: 1px;\n    margin-bottom: 14px;\n    padding-bottom: 8px;\n    border-bottom: 1px solid #c8a96e;\n}\n\n.satu-constitution .satu-const-article p {\n    font-size: 0.92rem;\n    color: #444444;\n    margin-bottom: 12px;\n}\n\n.satu-constitution ol {\n    padding-left: 24px;\n    margin-bottom: 14px;\n}\n\n.satu-constitution ol li {\n    font-size: 0.92rem;\n    color: #444444;\n    margin-bottom: 10px;\n    line-height: 1.75;\n    padding-left: 6px;\n}\n\n.satu-constitution ul {\n    padding-left: 24px;\n    margin-bottom: 10px;\n    margin-top: 8px;\n}\n\n.satu-constitution ul li {\n    font-size: 0.92rem;\n    color: #444444;\n    margin-bottom: 6px;\n    line-height: 1.75;\n    list-style-type: disc;\n}\n\n.satu-constitution ul ul {\n    margin-top: 6px;\n    padding-left: 24px;\n}\n\n.satu-constitution ul ul li {\n    list-style-type: circle;\n}\n\n.satu-constitution strong {\n    color: #333333;\n}\n\n@media (max-width: 600px) {\n    .satu-constitution { padding: 24px 16px 40px; }\n    .satu-constitution .satu-const-header h1 { font-size: 1rem; }\n}','hello-elementor-child-satu','','publish','closed','closed','','hello-elementor-child-satu','','','2026-05-20 20:23:15','2026-05-20 20:23:15','',0,'http://10.18.33.196/index.php/2026/05/20/hello-elementor-child-satu/',0,'custom_css','',0),
