", Palatino, Georgia, serif;\\n    font-size: 1.15rem;\\n    font-weight: 700;\\n    color: #6B1E1E;\\n    line-height: 1.6;\\n    margin-bottom: 16px;\\n    text-transform: uppercase;\\n    letter-spacing: 1px;\\n}\\n\\n.satu-constitution .satu-const-amendments {\\n    text-align: right;\\n    font-size: 0.85rem;\\n    color: #666666;\\n    line-height: 2;\\n    font-style: italic;\\n}\\n\\n.satu-constitution .satu-const-article {\\n    margin-bottom: 40px;\\n}\\n\\n.satu-constitution .satu-const-article h2 {\\n    font-family: Arial, Helvetica, sans-serif;\\n    font-size: 0.95rem;\\n    font-weight: 700;\\n    color: #6B1E1E;\\n    text-transform: uppercase;\\n    letter-spacing: 1px;\\n    margin-bottom: 14px;\\n    padding-bottom: 8px;\\n    border-bottom: 1px solid #c8a96e;\\n}\\n\\n.satu-constitution .satu-const-article p {\\n    font-size: 0.92rem;\\n    color: #444444;\\n    margin-bottom: 12px;\\n}\\n\\n.satu-constitution ol {\\n    padding-left: 24px;\\n    margin-bottom: 14px;\\n}\\n\\n.satu-constitution ol li {\\n    font-size: 0.92rem;\\n    color: #444444;\\n    margin-bottom: 10px;\\n    line-height: 1.75;\\n    padding-left: 6px;\\n}\\n\\n.satu-constitution ul {\\n    padding-left: 24px;\\n    margin-bottom: 10px;\\n    margin-top: 8px;\\n}\\n\\n.satu-constitution ul li {\\n    font-size: 0.92rem;\\n    color: #444444;\\n    margin-bottom: 6px;\\n    line-height: 1.75;\\n    list-style-type: disc;\\n}\\n\\n.satu-constitution ul ul {\\n    margin-top: 6px;\\n    padding-left: 24px;\\n}\\n\\n.satu-constitution ul ul li {\\n    list-style-type: circle;\\n}\\n\\n.satu-constitution strong {\\n    color: #333333;\\n}\\n\\n@media (max-width: 600px) {\\n    .satu-constitution { padding: 24px 16px 40px; }\\n    .satu-constitution .satu-const-header h1 { font-size: 1rem; }\\n}\",\n        \"type\": \"custom_css\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-05-20 20:23:15\"\n    }\n}','','','trash','closed','closed','','70120a21-b07c-4063-