(92,1,'2026-05-20 21:21:31','2026-05-20 21:21:31','<h2 \n		data-interaction-id=\"f5d366f\" \n		class=\"e-heading-base\" \n	>\n			About General Assembly\n		</h2>\n		<p>General Assembly meetings are held biennially. The next General Assembly meeting will be held in 2027. More details to follow.</p>					<h2 \n		data-interaction-id=\"6dc315f\" \n		class=\"e-heading-base\" \n	>\n			Previous Events\n		</h2>\n		[table id=1 /]<p><em>For more information, please refer to <a href=\"https://satu.ncku.edu.tw/p/412-1036-1789.php?Lang=en\">satu.ncku.edu.tw</a></em></p>','General Assembly','','publish','closed','closed','','general-assembly','','','2026-05-20 21:31:22','2026-05-20 21:31:22','',0,'http://10.18.33.196/?page_id=92',0,'page','',0),
